const items = $input.first().json?.data?.boards?.[0]?.groups?.[0]?.items_page?.items || [];
const today = new Date().toISOString().split('T')[0];
const dueToday = [];
const overdue = [];
const inProgress = [];
const noDue = [];
const priorityOrder = { 'High': 0, 'Medium': 1, 'Low': 2, '': 3 };
for (const item of items) {
  const status = (item.column_values || []).find(c => c.id === 'project_status');
  const due = (item.column_values || []).find(c => c.id === 'date');
  const pri = (item.column_values || []).find(c => c.id === 'priority');
  if (status?.text === 'Done') continue;
  const dueStr = due?.text?.split(' ')[0] || '';
  const record = { name: item.name, id: item.id, status: status?.text || 'Not Started', due: dueStr, priority: pri?.text || '' };
  if (dueStr && dueStr < today) overdue.push(record);
  else if (dueStr === today) dueToday.push(record);
  else if (status?.text === 'Working on it' || status?.text === 'In Progress') inProgress.push(record);
  else if (!dueStr) noDue.push(record);
}
const sortFn = (a, b) => (priorityOrder[a.priority] ?? 4) - (priorityOrder[b.priority] ?? 4);
overdue.sort(sortFn); dueToday.sort(sortFn); inProgress.sort(sortFn);

const blocks = [];

// Header
blocks.push({
  type: 'header',
  text: { type: 'plain_text', text: `🌅 Morning, Alex`, emoji: true }
});
blocks.push({
  type: 'context',
  elements: [
    { type: 'mrkdwn', text: `Here's your day — *${overdue.length}* overdue · *${dueToday.length}* due today · *${inProgress.length}* in progress · *${noDue.length}* no date` }
  ]
});

function renderItem(r) {
  // Main line: item name as link
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*<https://alex-it.monday.com/boards/5093821351/pulses/${r.id}|${r.name}>*`
    }
  });
  // Context line: metadata
  const meta = [];
  if (r.due) meta.push(`📅 Due ${r.due}`);
  if (r.priority) meta.push(`🔺 ${r.priority}`);
  if (r.status && r.status !== 'Not Started') meta.push(`⚙️ ${r.status}`);
  if (meta.length) {
    blocks.push({
      type: 'context',
      elements: [{ type: 'mrkdwn', text: meta.join('   ·   ') }]
    });
  }
}

function renderSection(emoji, title, records, limit) {
  if (!records.length) return;
  blocks.push({ type: 'divider' });
  blocks.push({
    type: 'header',
    text: { type: 'plain_text', text: `${emoji} ${title} (${records.length})`, emoji: true }
  });
  const shown = limit ? records.slice(0, limit) : records;
  shown.forEach(renderItem);
  if (limit && records.length > limit) {
    blocks.push({
      type: 'context',
      elements: [{ type: 'mrkdwn', text: `_...and ${records.length - limit} more_` }]
    });
  }
}

renderSection('🚨', 'Overdue', overdue);
renderSection('📅', 'Due today', dueToday);
renderSection('🛠️', 'In progress', inProgress);
renderSection('❓', 'No due date', noDue, 5);

if (!overdue.length && !dueToday.length && !inProgress.length) {
  blocks.push({ type: 'divider' });
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `🎉 *Nothing urgent.* Have a great day.` }
  });
}

const fallback = `Morning digest — ${overdue.length} overdue, ${dueToday.length} today, ${inProgress.length} in progress`;

return [{ json: { blocks, fallback, counts: { overdue: overdue.length, today: dueToday.length, inProgress: inProgress.length, noDue: noDue.length } } }];

